1	import { OpenCodeClient } from "../client/opencode.ts";
2	import type { AgentRunResult } from "../client/types.ts";
3	import type { EvalCase } from "../dataset/types.ts";
4	import type { LoadedConfig } from "../config/loader.ts";
5	import type { SandboxHandle, SandboxProvider } from "../sandbox/types.ts";
6	import { runValidators } from "../validator/engine.ts";
7	import { createLogger } from "../utils/logger.ts";
8	import { Timer, nowIso, formatDurationHuman } from "../utils/timer.ts";
9	import { withRetry } from "../utils/retry.ts";
10	import {
11	  emptyMetrics,
12	  finalizeTokens,
13	  recordToolCall,
14	  type CaseMetrics,
15	} from "./metrics.ts";
16	import type { CaseResult, CaseStatus, ValidatorResult } from "./types.ts";
17	
18	const log = createLogger("executor");
19	
20	export interface ExecutorDeps {
21	  loaded: LoadedConfig;
22	  provider: SandboxProvider;
23	}
