25	export async function executeCase(
26	  deps: ExecutorDeps,
27	  evalCase: EvalCase,
28	  signal: AbortSignal,
29	): Promise<CaseResult> {
30	  const { loaded, provider } = deps;
31	  const retries = loaded.config.execution.retries;
32	  let attempt = 0;
33	  let lastResult: CaseResult | null = null;
34	
35	  await withRetry(
36	    async () => {
37	      attempt += 1;
38	      lastResult = await runOnce(loaded, provider, evalCase, attempt, signal);
39	      if (lastResult.status === "errored") throw new Error(lastResult.error ?? "case errored");
40	    },
41	    {
42	      retries,
43	      signal,
44	      onAttempt: (n, err) => log.warn(`retry attempt ${n + 1}`, { err: (err as Error).message }),
45	    },
46	  ).catch(() => undefined);
47	
48	  return lastResult ?? errorResult(evalCase, "execution did not produce a result", attempt);
49	}
50	
51	async function runOnce(
52	  loaded: LoadedConfig,
53	  provider: SandboxProvider,
54	  evalCase: EvalCase,
55	  attempt: number,
56	  parentSignal: AbortSignal,
57	): Promise<CaseResult> {
58	  const timer = new Timer();
59	  const startedAt = nowIso();
60	  const metrics: CaseMetrics = emptyMetrics();
61	  const validatorResults: ValidatorResult[] = [];
62	  let agentText = "";
63	  let status: CaseStatus = "errored";
64	  let error: string | null = null;
65	
66	  const caseTimeout = evalCase.timeout_ms ?? loaded.config.execution.case_timeout_ms;
67	  const caseController = new AbortController();
68	  const timeoutTimer = setTimeout(() => caseController.abort(), caseTimeout);
69	  const onParentAbort = () => caseController.abort();
70	  parentSignal.addEventListener("abort", onParentAbort, { once: true });
71	
72	  let sandbox: SandboxHandle | null = null;
73	  let sessionId: string | null = null;
74	  let client: OpenCodeClient | null = null;
75	
76	  try {
77	    sandbox = await provider.create(
78	      {
79	        caseId: evalCase.id,
80	        workspaceSrc: loaded.workspacePath,
81	        workspaceOverlay: evalCase.workspace_overlay
82	          ? resolvePath(evalCase.workspace_overlay, loaded.baseDir)
83	          : null,
84	        opencodeConfig: buildOpencodeConfig(loaded),
85	        env: collectEnvFromProvider(loaded),
86	        timeoutMs: caseTimeout,
87	      },
88	      caseController.signal,
89	    );
90	
91	    client = new OpenCodeClient({
92	      baseUrl: `http://${sandbox.host}:${sandbox.port}`,
93	    });
94	    await client.waitReady(caseController.signal, 30_000);
95	
96	    for (const cmd of evalCase.setup_commands) {
97	      const r = await sandbox.exec(cmd, { signal: caseController.signal, timeoutMs: 60_000 });
98	      if (r.exitCode !== 0) {
99	        throw new Error(`setup command failed (exit ${r.exitCode}): ${cmd}\n${r.stderr}`);
100	      }
101	    }
102	
103	    const session = await client.createSession(`agent-eval/${evalCase.id}`, caseController.signal);
104	    sessionId = session.id;
105	
106	    const run = await client.sendMessage(
107	      { sessionId, text: evalCase.prompt, signal: caseController.signal },
108	      {
109	        onMessageStart: () => {
110	          metrics.messages += 1;
111	        },
112	        onUsage: (usage) => {
113	          metrics.tokens = usage;
114	        },
115	        onToolCall: (call) => {
116	          recordToolCall(metrics.tool_calls, call.toolName, false);
117	        },
118	        onToolResult: (result) => {
119	          if (result.errored) metrics.tool_calls.errors += 1;
120	        },
121	      },
122	    );
123	    agentText = run.text;
124	    metrics.tokens = finalizeTokens(run.usage);
125	    if (metrics.messages === 0) metrics.messages = run.messages;
126	
127	    // Populate tool_calls from the messages API result
128	    for (const call of run.toolCalls) {
129	      recordToolCall(metrics.tool_calls, call.toolName, false);
130	    }
131	    for (const result of run.toolResults) {
132	      if (result.errored) metrics.tool_calls.errors += 1;
133	    }
134	
135	    for (const cmd of evalCase.teardown_commands) {
136	      await sandbox
137	        .exec(cmd, { signal: caseController.signal, timeoutMs: 60_000 })
138	        .catch((err) => log.warn("teardown failed", { case: evalCase.id, err: (err as Error).message }));
139	    }
140	
141	    const validation = await runValidators({
142	      loaded,
143	      sandbox,
144	      evalCase,
145	      agentRun: run,
146	      signal: caseController.signal,
147	    });
148	    validatorResults.push(...validation.results);
149	
150	    status = decideStatus(evalCase, validation.results);
151	    error = null;
152	    return finalize({
153	      evalCase,
154	      status,
155	      validatorResults,
156	      agentText,
157	      error,
158	      metrics,
159	      durationMs: timer.elapsedMs(),
160	      startedAt,
161	      attempt,
162	      score: validation.aggregateScore,
163	    });
164	  } catch (err) {
165	    if (caseController.signal.aborted && !parentSignal.aborted) {
166	      status = "timeout";
167	      error = `case exceeded timeout of ${caseTimeout}ms`;
168	    } else {
169	      status = "errored";
170	      error = (err as Error).message;
171	    }
172	    return finalize({
173	      evalCase,
174	      status,
175	      validatorResults,
176	      agentText,
177	      error,
178	      metrics,
179	      durationMs: timer.elapsedMs(),
180	      startedAt,
181	      attempt,
182	    });
183	  } finally {
184	    clearTimeout(timeoutTimer);
185	    parentSignal.removeEventListener("abort", onParentAbort);
186	    if (client && sessionId) {
187	      await client.deleteSession(sessionId).catch(() => undefined);
188	    }
189	    if (sandbox) {
190	      await sandbox.destroy().catch((err) =>
191	        log.warn("sandbox destroy failed", { case: evalCase.id, err: (err as Error).message }),
192	      );
193	    }
194	  }
195	}
