197	interface FinalizeArgs {
198	  evalCase: EvalCase;
199	  status: CaseStatus;
200	  validatorResults: ValidatorResult[];
201	  agentText: string;
202	  error: string | null;
203	  metrics: CaseMetrics;
204	  durationMs: number;
205	  startedAt: string;
206	  attempt: number;
207	  score?: number | undefined;
208	}
209	
210	function finalize(args: FinalizeArgs): CaseResult {
211	  return {
212	    id: args.evalCase.id,
213	    name: args.evalCase.name ?? args.evalCase.id,
214	    type: args.evalCase.type,
215	    status: args.status,
216	    score: args.score,
217	    duration_ms: args.durationMs,
218	    duration: formatDurationHuman(args.durationMs),
219	    started_at: args.startedAt,
220	    finished_at: nowIso(),
221	    validators: args.validatorResults,
222	    agent_output_summary: summarize(args.agentText),
223	    error: args.error,
224	    metrics: args.metrics,
225	    attempt: args.attempt,
226	  };
227	}
228	
229	function errorResult(evalCase: EvalCase, message: string, attempt: number): CaseResult {
230	  return {
231	    id: evalCase.id,
232	    name: evalCase.name ?? evalCase.id,
233	    type: evalCase.type,
234	    status: "errored",
235	    duration_ms: 0,
236	    duration: "0ms",
237	    started_at: nowIso(),
238	    finished_at: nowIso(),
239	    validators: [],
240	    agent_output_summary: "",
241	    error: message,
242	    metrics: emptyMetrics(),
243	    attempt,
244	  };
245	}
246	
247	function decideStatus(evalCase: EvalCase, results: ValidatorResult[]): CaseStatus {
248	  if (evalCase.type === "scoring") {
249	    return results.every((r) => r.passed || r.score !== undefined) ? "passed" : "failed";
250	  }
251	  if (results.length === 0) return "passed";
252	  return results.every((r) => r.passed) ? "passed" : "failed";
253	}
254	
255	function summarize(text: string): string {
256	  const trimmed = text.trim();
257	  if (trimmed.length <= 800) return trimmed;
258	  return `${trimmed.slice(0, 400)}\n…\n${trimmed.slice(-300)}`;
259	}
260	
261	function buildOpencodeConfig(loaded: LoadedConfig): Record<string, unknown> {
262	  const cfg = loaded.config.opencode;
263	  return {
264	    $schema: "https://opencode.ai/config.json",
265	    model: cfg.model,
266	    provider: cfg.provider,
267	    mcp: cfg.mcp,
268	    permission: cfg.permission,
269	    skills: cfg.skills,
270	    ...(cfg.extra ?? {}),
271	  };
272	}
273	
274	function collectEnvFromProvider(loaded: LoadedConfig): Record<string, string> {
275	  const env: Record<string, string> = {};
276	  walkForEnv(loaded.config.opencode.provider, env);
277	  if (loaded.config.judge?.api_key_env) {
278	    const v = process.env[loaded.config.judge.api_key_env];
279	    if (v) env[loaded.config.judge.api_key_env] = v;
280	  }
281	  return env;
282	}
283	
284	function walkForEnv(value: unknown, out: Record<string, string>): void {
285	  if (!value || typeof value !== "object") return;
286	  if (Array.isArray(value)) {
287	    for (const v of value) walkForEnv(v, out);
288	    return;
289	  }
290	  for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
291	    if ((k === "api_key_env" || k === "apiKeyEnv") && typeof v === "string") {
292	      const resolved = process.env[v];
293	      if (resolved) out[v] = resolved;
294	    } else {
295	      walkForEnv(v, out);
296	    }
297	  }
298	}
299	
300	function resolvePath(p: string, base: string): string {
301	  if (p.startsWith("/")) return p;
302	  return `${base}/${p}`;
303	}
