20	const log = createLogger("sandbox:docker");
21	
22	export class DockerSandboxProvider implements SandboxProvider {
23	  readonly mode = "docker" as const;
24	  private docker: Docker;
25	  private active = new Set<DockerSandboxHandle>();
26	
27	  constructor(private config: EvalConfig, private portPool: PortPool) {
28	    this.docker = new Docker();
29	  }
30	
31	  async create(spec: SandboxSpec, signal: AbortSignal): Promise<SandboxHandle> {
32	    const port = await this.portPool.acquire(signal);
33	    const stagingDir = await mkdtemp(join(tmpdir(), `agent-eval-stage-${spec.caseId}-`));
34	    let container: Docker.Container | null = null;
35	    try {
36	      if (spec.workspaceSrc) {
37	        await cp(spec.workspaceSrc, stagingDir, { recursive: true });
38	      }
39	      if (spec.workspaceOverlay) {
40	        await cp(spec.workspaceOverlay, stagingDir, { recursive: true });
41	      }
42	      await writeFile(
43	        join(stagingDir, "opencode.json"),
44	        JSON.stringify(spec.opencodeConfig, null, 2),
45	        "utf-8",
46	      );
47	
48	      const envArr = Object.entries({ ...this.config.sandbox.env, ...spec.env }).map(
49	        ([k, v]) => `${k}=${v}`,
50	      );
51	
52	      container = await this.docker.createContainer({
53	        Image: this.config.sandbox.image,
54	        name: `agent-eval-${spec.caseId}-${port}`,
55	        Cmd: ["opencode", "serve", "--port", String(port), "--hostname", "0.0.0.0"],
56	        WorkingDir: "/workspace",
57	        Env: envArr,
58	        Tty: false,
59	        ExposedPorts: { [`${port}/tcp`]: {} },
60	        HostConfig: {
61	          AutoRemove: false,
62	          Memory: parseMemory(this.config.sandbox.memory_limit),
63	          NanoCpus: Math.round(parseFloat(this.config.sandbox.cpu_limit) * 1e9),
64	          NetworkMode: this.config.sandbox.network,
65	          PortBindings: { [`${port}/tcp`]: [{ HostPort: String(port) }] },
66	        },
67	      });
68	
69	      const tarStream = await packDirectory(stagingDir);
70	      await container.putArchive(tarStream, { path: "/workspace" });
71	
72	      await container.start();
73	
74	      const handle = new DockerSandboxHandle({
75	        caseId: spec.caseId,
76	        port,
77	        container,
78	        stagingDir,
79	        portPool: this.portPool,
80	        onDestroyed: () => this.active.delete(handle),
81	      });
82	      this.active.add(handle);
83	      return handle;
84	    } catch (err) {
85	      this.portPool.release(port);
86	      if (container) await container.remove({ force: true }).catch(() => {});
87	      await rm(stagingDir, { recursive: true, force: true }).catch(() => {});
88	      throw err;
89	    }
90	  }
91	
92	  async shutdown(): Promise<void> {
93	    await Promise.allSettled([...this.active].map((h) => h.destroy()));
94	  }
95	}
