106	class DockerSandboxHandle implements SandboxHandle {
107	  readonly mode = "docker" as const;
108	  readonly host = "127.0.0.1";
109	  readonly id: string;
110	  readonly port: number;
111	  readonly workdir = "/workspace";
112	  private container: Docker.Container;
113	  private stagingDir: string;
114	  private portPool: PortPool;
115	  private destroyed = false;
116	  private onDestroyed: () => void;
117	
118	  constructor(opts: DockerHandleOpts) {
119	    this.id = `docker-${opts.caseId}`;
120	    this.port = opts.port;
121	    this.container = opts.container;
122	    this.stagingDir = opts.stagingDir;
123	    this.portPool = opts.portPool;
124	    this.onDestroyed = opts.onDestroyed;
125	  }
126	
127	  async exec(command: string, options: ExecOptions = {}): Promise<ExecResult> {
128	    const start = performance.now();
129	    const shell = options.shell ?? "/bin/sh";
130	    const env = options.env
131	      ? Object.entries(options.env).map(([k, v]) => `${k}=${v}`)
132	      : undefined;
133	
134	    const exec = await this.container.exec({
135	      Cmd: [shell, "-c", command],
136	      WorkingDir: options.cwd ?? "/workspace",
137	      Env: env,
138	      AttachStdout: true,
139	      AttachStderr: true,
140	      AttachStdin: options.stdin !== undefined,
141	      Tty: false,
142	    });
143	
144	    let stdout = "";
145	    let stderr = "";
146	    let timedOut = false;
147	
148	    const stream = await exec.start({ hijack: true, stdin: options.stdin !== undefined });
149	    if (options.stdin !== undefined) {
150	      stream.write(options.stdin);
151	      stream.end();
152	    }
153	
154	    const out = collectMultiplexed(stream, (s, e) => {
155	      stdout += s;
156	      stderr += e;
157	    });
158	
159	    const timer = options.timeoutMs
160	      ? setTimeout(() => {
161	          timedOut = true;
162	          stream.destroy();
163	        }, options.timeoutMs)
164	      : null;
165	    const onAbort = () => {
166	      timedOut = true;
167	      stream.destroy();
168	    };
169	    options.signal?.addEventListener("abort", onAbort, { once: true });
170	
171	    try {
172	      await out;
173	    } finally {
174	      if (timer) clearTimeout(timer);
175	      options.signal?.removeEventListener("abort", onAbort);
176	    }
177	
178	    const inspect = await exec.inspect();
179	    return {
180	      exitCode: inspect.ExitCode ?? -1,
181	      stdout,
182	      stderr,
183	      timedOut,
184	      durationMs: Math.round(performance.now() - start),
185	    };
186	  }
187	
188	  async readFile(path: string): Promise<string> {
189	    const target = this.resolveInWorkdir(path);
190	    const stream = await this.container.getArchive({ path: target });
191	    return readSingleFileFromTar(stream);
192	  }
193	
194	  async writeFile(path: string, content: string): Promise<void> {
195	    const target = this.resolveInWorkdir(path);
196	    const tar = pack();
197	    tar.entry({ name: posixBasename(target), mode: 0o644 }, content);
198	    tar.finalize();
199	    const dir = posixDirname(target);
200	    await this.container.putArchive(Readable.from(streamFromTar(tar)), { path: dir });
201	  }
202	
203	  async fileExists(path: string): Promise<boolean> {
204	    try {
205	      await this.container.infoArchive({ path: this.resolveInWorkdir(path) });
206	      return true;
207	    } catch {
208	      return false;
209	    }
210	  }
211	
212	  async destroy(): Promise<void> {
213	    if (this.destroyed) return;
214	    this.destroyed = true;
215	    try {
216	      await this.container.stop({ t: 2 }).catch(() => {});
217	      await this.container.remove({ force: true }).catch(() => {});
218	    } finally {
219	      this.portPool.release(this.port);
220	      await rm(this.stagingDir, { recursive: true, force: true }).catch(() => {});
221	      this.onDestroyed();
222	    }
223	  }
224	
225	  private resolveInWorkdir(path: string): string {
226	    if (path.startsWith("/")) return path;
227	    return `${this.workdir}/${path}`;
228	  }
229	}
