231	function parseMemory(s: string): number {
232	  const match = /^(\d+(?:\.\d+)?)\s*([kmg]?)b?$/i.exec(s.trim());
233	  if (!match) throw new Error(`invalid memory_limit: ${s}`);
234	  const n = parseFloat(match[1]!);
235	  const unit = (match[2] ?? "").toLowerCase();
236	  const mult = unit === "g" ? 1024 ** 3 : unit === "m" ? 1024 ** 2 : unit === "k" ? 1024 : 1;
237	  return Math.round(n * mult);
238	}
