240	function packDirectory(dir: string): Promise<Readable> {
241	  // Use tar-stream to recursively pack
242	  return new Promise(async (resolveTar, rejectTar) => {
243	    const tar = pack();
244	    try {
245	      const { readdir, stat: fsStat, readFile: fsRead } = await import("node:fs/promises");
246	      async function walk(current: string, rel: string): Promise<void> {
247	        const entries = await readdir(current);
248	        for (const entry of entries) {
249	          const full = join(current, entry);
250	          const relPath = rel ? `${rel}/${entry}` : entry;
251	          const st = await fsStat(full);
252	          if (st.isDirectory()) {
253	            await new Promise<void>((res, rej) =>
254	              tar.entry({ name: `${relPath}/`, type: "directory", mode: st.mode & 0o777 }, (err) =>
255	                err ? rej(err) : res(),
256	              ),
257	            );
258	            await walk(full, relPath);
259	          } else if (st.isFile()) {
260	            const content = await fsRead(full);
261	            await new Promise<void>((res, rej) =>
262	              tar.entry({ name: relPath, mode: st.mode & 0o777, size: content.length }, content, (err) =>
263	                err ? rej(err) : res(),
264	              ),
265	            );
266	          }
267	        }
268	      }
269	      await walk(dir, "");
270	      tar.finalize();
271	      resolveTar(tar as unknown as Readable);
272	    } catch (err) {
273	      rejectTar(err);
274	    }
275	  });
276	}
