278	async function* streamFromTar(tar: ReturnType<typeof pack>): AsyncGenerator<Buffer> {
279	  for await (const chunk of tar as unknown as AsyncIterable<Buffer>) {
280	    yield chunk;
281	  }
282	}
283	
284	function readSingleFileFromTar(stream: NodeJS.ReadableStream): Promise<string> {
285	  return new Promise((resolveRead, rejectRead) => {
286	    const ex = extract();
287	    let result = "";
288	    let found = false;
289	    ex.on("entry", (header, entryStream, next) => {
290	      if (header.type === "file" && !found) {
291	        found = true;
292	        const chunks: Buffer[] = [];
293	        entryStream.on("data", (c: Buffer) => chunks.push(c));
294	        entryStream.on("end", () => {
295	          result = Buffer.concat(chunks).toString("utf-8");
296	          next();
297	        });
298	        entryStream.resume();
299	      } else {
300	        entryStream.on("end", next);
301	        entryStream.resume();
302	      }
303	    });
304	    ex.on("finish", () => resolveRead(result));
