310	function collectMultiplexed(
311	  stream: NodeJS.ReadableStream,
312	  onChunk: (stdout: string, stderr: string) => void,
313	): Promise<void> {
314	  return new Promise((resolveCollect, rejectCollect) => {
315	    let buf = Buffer.alloc(0);
316	    stream.on("data", (chunk: Buffer) => {
317	      buf = Buffer.concat([buf, chunk]);
318	      while (buf.length >= 8) {
319	        const streamType = buf[0];
320	        const size = buf.readUInt32BE(4);
321	        if (buf.length < 8 + size) break;
322	        const payload = buf.slice(8, 8 + size).toString("utf-8");
323	        buf = buf.slice(8 + size);
324	        if (streamType === 1) onChunk(payload, "");
325	        else if (streamType === 2) onChunk("", payload);
326	      }
327	    });
328	    stream.on("end", () => resolveCollect());
329	    stream.on("error", rejectCollect);
330	  });
331	}
