162	export async function runShell(command: string, options: ExecOptions = {}): Promise<ExecResult> {
163	  const start = performance.now();
164	  const shell = options.shell ?? "/bin/sh";
165	  return new Promise((resolveExec) => {
166	    const proc = spawn(shell, ["-c", command], {
167	      cwd: options.cwd,
168	      env: options.env ?? mergeEnv(process.env),
169	      stdio: ["pipe", "pipe", "pipe"],
170	    });
171	
172	    let stdout = "";
173	    let stderr = "";
174	    let timedOut = false;
175	
176	    const timer = options.timeoutMs
177	      ? setTimeout(() => {
178	          timedOut = true;
179	          proc.kill("SIGKILL");
180	        }, options.timeoutMs)
181	      : null;
182	
183	    const onAbort = () => {
184	      timedOut = true;
185	      proc.kill("SIGKILL");
186	    };
187	    options.signal?.addEventListener("abort", onAbort, { once: true });
188	
189	    proc.stdout?.on("data", (c: Buffer) => {
190	      stdout += c.toString();
191	    });
192	    proc.stderr?.on("data", (c: Buffer) => {
193	      stderr += c.toString();
194	    });
195	
196	    if (options.stdin !== undefined) {
197	      proc.stdin?.write(options.stdin);
198	      proc.stdin?.end();
199	    }
200	
201	    proc.on("close", (code) => {
202	      if (timer) clearTimeout(timer);
203	      options.signal?.removeEventListener("abort", onAbort);
204	      resolveExec({
205	        exitCode: code ?? -1,
206	        stdout,
207	        stderr,
208	        timedOut,
209	        durationMs: Math.round(performance.now() - start),
210	      });
211	    });
212	  });
213	}
