215	async function waitForExit(proc: ReturnType<typeof spawn>, ms: number): Promise<boolean> {
216	  if (proc.exitCode !== null) return true;
217	  return new Promise((resolveExit) => {
218	    const onExit = () => {
219	      cleanup();
220	      resolveExit(true);
221	    };
222	    const t = setTimeout(() => {
223	      cleanup();
224	      resolveExit(false);
225	    }, ms);
226	    function cleanup() {
227	      clearTimeout(t);
228	      proc.off("exit", onExit);
229	    }
230	    proc.on("exit", onExit);
231	  });
232	}
