234	function mergeEnv(
235	  base: NodeJS.ProcessEnv,
236	  ...overrides: (Record<string, string> | undefined)[]
237	): Record<string, string> {
238	  const out: Record<string, string> = {};
239	  for (const [k, v] of Object.entries(base)) {
240	    if (typeof v === "string") out[k] = v;
241	  }
242	  for (const o of overrides) {
243	    if (!o) continue;
244	    for (const [k, v] of Object.entries(o)) out[k] = v;
245	  }
246	  return out;
247	}
